BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?prop ?valCount (SAMPLE(?value) AS ?exampleValue) WHERE {
  {
    ?elem rdf:type ?type ;
          vocab:NamedElement_name ?name .
    FILTER( CONTAINS(LCASE(STR(?name)), "aps%20operational%20blackbox%20specification%20jpl") ||
            CONTAINS(LCASE(STR(?name)), "aps operational blackbox specification jpl") )
    OPTIONAL { ?elem ?prop ?value . }
  }
  BIND(1 AS ?dummy)
  OPTIONAL {
    SELECT ?prop (COUNT(*) AS ?valCount) (SAMPLE(?value) AS ?value) WHERE {
      ?elem rdf:type ?type ; vocab:NamedElement_name ?name .
      FILTER( CONTAINS(LCASE(STR(?name)), "aps operational blackbox specification jpl") )
      ?elem ?prop ?value .
    }
    GROUP BY ?prop
  }
} GROUP BY ?prop ?valCount
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?type ?name WHERE {
  ?elem rdf:type ?type ;
        vocab:NamedElement_name ?name .
  FILTER(
    CONTAINS(LCASE(STR(?name)), "aps%20operational%20blackbox") &&
    (CONTAINS(LCASE(STR(?name)), "jpl") || CONTAINS(LCASE(STR(?name)), "tmt"))
  )
}
ORDER BY ?name
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?type ?name WHERE {
