BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?parentName ?child ?childType ?childName WHERE {
  VALUES (?parent ?parentName) {
    (
      <http://api.koneksys.com/cameo/TMT/part%20property/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::01%2520Components::Operational::APS::Conceptual%2520Design::APS%2520Mission%2520Conceptual::APS%2520Operational%2520Blackbox>
      "TMT: APS Operational Blackbox"
    )
    (
      <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::01%2520Components::Operational::APS::Black%2520Box%2520Specification::Structure::APS%2520Operational%2520Blackbox%2520Specification%2520JPL>
      "JPL: APS Operational Blackbox Specification JPL"
    )
  }
  ?parent vocab:Element_ownedElement+ ?child .
  ?child rdf:type ?childType .
  OPTIONAL { ?child vocab:NamedElement_name ?childName . }
}
ORDER BY ?parentName ?childType ?childName
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?bbName ?inst ?instName ?classifierName ?slotName ?slotValueName WHERE {
  VALUES (?bb ?bbName) {
    (
      <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::01%2520Components::Operational::APS::Black%2520Box%2520Specification::Structure::APS%2520Operational%2520Blackbox%2520Specification%2520JPL>
      "JPL: APS Operational Blackbox Specification"
    )
    (
      <http://api.koneksys.com/cameo/TMT/part%20property/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::01%2520Components::Operational::APS::Conceptual%2520Design::APS%2520Mission%2520Conceptual::APS%2520Operational%2520Blackbox>
      "TMT: APS Operational Blackbox"
    )
  }

  ?bb vocab:Element_ownedElement+ ?inst .
  ?inst rdf:type vocab:instance%20specification .

  OPTIONAL { ?inst vocab:NamedElement_name ?instName . }
  OPTIONAL { ?inst vocab:InstanceSpecification_classifier ?classifier . }
  OPTIONAL { ?classifier vocab:NamedElement_name ?classifierName . }

  OPTIONAL {
    ?inst vocab:InstanceSpecification_slot ?slot .
    OPTIONAL { ?slot vocab:NamedElement_name ?slotName . }
    OPTIONAL { ?slot vocab:Slot_value ?slotValue . }
    OPTIONAL { ?slotValue vocab:NamedElement_name ?slotValueName . }
  }
}
ORDER BY ?bbName ?instName ?classifierName
LIMIT 25

