BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?tmtChild ?tmtChildType ?tmtChildName ?literalValue WHERE {
  <http://api.koneksys.com/cameo/TMT/part%20property/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::01%2520Components::Operational::APS::Conceptual%2520Design::APS%2520Mission%2520Conceptual::APS%2520Operational%2520Blackbox>
    vocab:Element_ownedElement+ ?tmtChild .

  ?tmtChild rdf:type ?tmtChildType .
  OPTIONAL { ?tmtChild vocab:NamedElement_name ?tmtChildName . }
  OPTIONAL { ?tmtChild rdf:value ?literalValue . }
  OPTIONAL { ?tmtChild vocab:NamedElement_name ?literalValue . }
  FILTER(?tmtChildType = vocab:literal%20integer || ?tmtChildType = vocab:literal%20unlimited%20natural || ?tmtChildType = vocab:instance%20specification)
}
LIMIT 25
